import { useEffect, useRef } from 'react';
import * as THREE from 'three';

export function ThreeFogSphere() {
  const mountRef = useRef(null);

  useEffect(() => {
    const mount = mountRef.current;
    if (!mount) return;

    const width = mount.clientWidth;
    const height = mount.clientHeight || 300;

    // Scene, Camera, Renderer
    const scene = new THREE.Scene();
    scene.fog = new THREE.FogExp2(0x0f0c1b, 0.015);

    const camera = new THREE.PerspectiveCamera(75, width / height, 0.1, 1000);
    camera.position.z = 8;

    const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    renderer.setSize(width, height);
    renderer.setPixelRatio(window.devicePixelRatio);
    mount.appendChild(renderer.domElement);

    // Sphere Geometry & Material
    const geometry = new THREE.IcosahedronGeometry(3, 4);
    const material = new THREE.MeshBasicMaterial({
      color: 0x00adb5,
      wireframe: true,
      transparent: true,
      opacity: 0.8
    });
    const sphere = new THREE.Mesh(geometry, material);
    scene.add(sphere);

    // Ambient & Directional Light
    const ambientLight = new THREE.AmbientLight(0xffffff, 0.5);
    scene.add(ambientLight);

    // Mouse Tracking
    let mouseX = 0;
    let mouseY = 0;
    const handleMouseMove = (e) => {
      const rect = mount.getBoundingClientRect();
      mouseX = ((e.clientX - rect.left) / width) * 2 - 1;
      mouseY = -((e.clientY - rect.top) / height) * 2 + 1;
    };
    mount.addEventListener('mousemove', handleMouseMove);

    // Resize handler
    const handleResize = () => {
      const w = mount.clientWidth;
      const h = mount.clientHeight || 300;
      camera.aspect = w / h;
      camera.updateProjectionMatrix();
      renderer.setSize(w, h);
    };
    window.addEventListener('resize', handleResize);

    // Animation Loop
    let animationId;
    const animate = () => {
      animationId = requestAnimationFrame(animate);

      // Rotate based on time and mouse
      sphere.rotation.y += 0.005;
      sphere.rotation.x += 0.002;

      // Slow camera tracking
      camera.position.x += (mouseX * 4 - camera.position.x) * 0.05;
      camera.position.y += (mouseY * 4 - camera.position.y) * 0.05;
      camera.lookAt(scene.position);

      renderer.render(scene, camera);
    };
    animate();

    // Cleanup
    return () => {
      cancelAnimationFrame(animationId);
      mount.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('resize', handleResize);
      if (mount.contains(renderer.domElement)) {
        mount.removeChild(renderer.domElement);
      }
      geometry.dispose();
      material.dispose();
      renderer.dispose();
    };
  }, []);

  return (
    <div className="relative w-full h-[350px] border border-border bg-[#0f0c1b] overflow-hidden rounded-2xl">
      <div ref={mountRef} className="absolute inset-0 block w-full h-full" />
      <div className="absolute inset-0 flex items-center justify-center text-center p-6 z-10 pointer-events-none select-none">
        <div>
          <h4 className="text-lg font-bold tracking-tight text-white">Interactive WebGL Sphere</h4>
          <p className="text-xs text-neutral-400 mt-0.5">Three.js wireframe icosahedron grid</p>
        </div>
      </div>
    </div>
  );
}

import { useEffect, useRef } from 'react';
import * as THREE from 'three';

export function ThreeParticleTrail() {
  const mountRef = useRef(null);

  useEffect(() => {
    const mount = mountRef.current;
    if (!mount) return;

    const width = mount.clientWidth;
    const height = mount.clientHeight || 300;

    const scene = new THREE.Scene();
    const camera = new THREE.PerspectiveCamera(60, width / height, 1, 1000);
    camera.position.z = 500;

    const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    renderer.setSize(width, height);
    renderer.setPixelRatio(window.devicePixelRatio);
    mount.appendChild(renderer.domElement);

    // Create particle buffer system
    const maxParticles = 150;
    const geometry = new THREE.BufferGeometry();
    const positions = new Float32Array(maxParticles * 3);
    const sizes = new Float32Array(maxParticles);
    const colors = new Float32Array(maxParticles * 3);

    // Set initial positions offscreen
    for (let i = 0; i < maxParticles; i++) {
      positions[i * 3] = 9999;
      positions[i * 3 + 1] = 9999;
      positions[i * 3 + 2] = 0;
      sizes[i] = Math.random() * 5 + 2;

      colors[i * 3] = 0.0;
      colors[i * 3 + 1] = 0.67;
      colors[i * 3 + 2] = 0.70; // Cyan
    }

    geometry.setAttribute('position', new THREE.BufferAttribute(positions, 3));
    geometry.setAttribute('color', new THREE.BufferAttribute(colors, 3));

    const material = new THREE.PointsMaterial({
      size: 4,
      vertexColors: true,
      transparent: true,
      opacity: 0.8
    });

    const particleSystem = new THREE.Points(geometry, material);
    scene.add(particleSystem);

    let mouseX = 0;
    let mouseY = 0;
    let currentIdx = 0;

    const handleMouseMove = (e) => {
      const rect = mount.getBoundingClientRect();
      // Translate coordinate space to WebGL frustum projection
      mouseX = ((e.clientX - rect.left) / width) * 1000 - 500;
      mouseY = -((e.clientY - rect.top) / height) * 600 + 300;

      const posArr = geometry.attributes.position.array;
      posArr[currentIdx * 3] = mouseX;
      posArr[currentIdx * 3 + 1] = mouseY;
      posArr[currentIdx * 3 + 2] = (Math.random() - 0.5) * 50;

      currentIdx = (currentIdx + 1) % maxParticles;
      geometry.attributes.position.needsUpdate = true;
    };
    mount.addEventListener('mousemove', handleMouseMove);

    const handleResize = () => {
      const w = mount.clientWidth;
      const h = mount.clientHeight || 300;
      camera.aspect = w / h;
      camera.updateProjectionMatrix();
      renderer.setSize(w, h);
    };
    window.addEventListener('resize', handleResize);

    // Animation Loop
    let animationId;
    const animate = () => {
      animationId = requestAnimationFrame(animate);

      // Slowly fade/decay active positions downwards
      const posArr = geometry.attributes.position.array;
      for (let i = 0; i < maxParticles; i++) {
        if (posArr[i * 3] !== 9999) {
          posArr[i * 3 + 1] -= 0.8; // Float downwards
          posArr[i * 3] += (Math.random() - 0.5) * 2; // Drift side-to-side
        }
      }
      geometry.attributes.position.needsUpdate = true;
      renderer.render(scene, camera);
    };
    animate();

    return () => {
      cancelAnimationFrame(animationId);
      mount.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('resize', handleResize);
      if (mount.contains(renderer.domElement)) {
        mount.removeChild(renderer.domElement);
      }
      geometry.dispose();
      material.dispose();
      renderer.dispose();
    };
  }, []);

  return (
    <div className="relative w-full h-[350px] border border-border bg-neutral-950 overflow-hidden rounded-2xl cursor-pointer">
      <div ref={mountRef} className="absolute inset-0 block w-full h-full" />
      <div className="absolute inset-0 flex items-center justify-center text-center p-6 z-10 pointer-events-none select-none">
        <div>
          <h4 className="text-lg font-bold tracking-tight text-white">WebGL Shooting Star Trail</h4>
          <p className="text-xs text-neutral-400 mt-0.5">BufferGeometry particle systems trailing cursor coords</p>
        </div>
      </div>
    </div>
  );
}
